// ───────────────────────────────────────────────────────────────
// 1. CLEANUP ORPHANED VECTORS
// ───────────────────────────────────────────────────────────────
// Database maintenance — removes orphaned vector embeddings and history entries

// External packages
import Database from 'better-sqlite3';
import { load as loadSqliteVec } from 'sqlite-vec';

// Shared config
import { DB_PATH } from '@spec-kit/shared/paths';
import { acquireDbInstanceLock, releaseDbInstanceLocks } from '@spec-kit/mcp-server/api/db-lock';
import { isMainModule } from '../lib/esm-entry.js';

/* ───────────────────────────────────────────────────────────────
   1. INTERFACES

display.text:
// ---------------------------------------------------------------
// MODULE: Cleanup Orphaned Vectors
// ---------------------------------------------------------------

// ───────────────────────────────────────────────────────────────
// 1. CLEANUP ORPHANED VECTORS
// ───────────────────────────────────────────────────────────────
// Database maintenance — removes orphaned vector embeddings and history entries

// External packages
import Database from 'better-sqlite3';
import { load as loadSqliteVec } from 'sqlite-vec';

// Shared config
import { DB_PATH } from '@spec-kit/shared/paths';
import { acquireDbInstanceLock, releaseDbInstanceLocks } from '@spec-kit/mcp-server/api/db-lock';
import { isMainModule } from '../lib/esm-entry.js';

/* ───────────────────────────────────────────────────────────────
   1. INTERFACES
------------------------------------------------------------------*/

interface CountResult {
  count: number;
}

/* ───────────────────────────────────────────────────────────────
   2. CONFIGURATION
------------------------------------------------------------------*/

const dbPath: string = DB_PATH;

/* ───────────────────────────────────────────────────────────────
   2.1 HELP TEXT
------------------------------------------------------------------*/

const HELP_TEXT = `
cleanup-orphaned-vectors — Remove orphaned vector embeddings and history entries

Usage: node cleanup-orphaned-vectors.js [options]

Options:
  --dry-run           Preview what would be deleted without making changes
  --help, -h          Show this help message

Examples:
  node cleanup-orphaned-vectors.js                # Run cleanup
  node cleanup-orphaned-vectors.js --dry-run      # Preview only
`;

if (process.argv.includes('--help') || process.argv.includes('-h')) {
  console.log(HELP_TEXT);
  process.exit(0);
}

/* ───────────────────────────────────────────────────────────────
   3. MAIN FUNCTION
------------------------------------------------------------------*/

async function main(): Promise<void> {
  const dryRun: boolean = process.argv.includes('--dry-run');
  let database: InstanceType<typeof Database> | null = null;
  try {
    if (dryRun) {
      console.log('=== DRY-RUN MODE — no changes will be made ===\n');
    }
    console.log('Opening database:', dbPath);
    // Single-writer guard: refuse to mutate a database a live daemon (or
    // another maintenance run) currently owns — stop the daemon first.
    acquireDbInstanceLock(dbPath);
    database = new Database(dbPath);
    loadSqliteVec(database);

    let totalCleaned = 0;

    // STEP 1: Discover orphaned entries across all tables
    console.log('\n[Step 1] Finding orphaned memory_history entries...');
    let orphanedHistoryCount = 0;
    let hasHistoryTable = true;
    try {
      const orphanedHistory = database.prepare(`
        SELECT COUNT(*) as count
        FROM memory_history h
        LEFT JOIN memory_index m ON h.memory_id = m.id
        WHERE m.id IS NULL
      `).get() as CountResult;

      orphanedHistoryCount = orphanedHistory.count;

      if (orphanedHistoryCount > 0) {
        console.log(`Found ${orphanedHistoryCount} orphaned history entries`);
      } else {
        console.log('No orphaned history entries found');
      }
    } catch (e: unknown) {
      const errMsg = e instanceof Error ? e.message : String(e);
      if (errMsg.includes('no such table')) {
        hasHistoryTable = false;
      } else {
        console.warn('memory_history discovery warning:', errMsg);
      }
    }

    console.log('\n[Step 2] Finding orphaned vector entries...');
    const orphanedVectors = database.prepare(`
      SELECT COUNT(*) as count
      FROM vec_memories v
      LEFT JOIN memory_index m ON v.rowid = m.id
      WHERE m.id IS NULL
    `).get() as CountResult;

    const orphanedVectorCount = orphanedVectors.count;
    console.log(`Found ${orphanedVectorCount} orphaned vectors`);

    // STEP 2: Delete all orphans in a single atomic transaction
    // ISS-B04-002 fix — wrapping history + vector cleanup in one
    // Transaction prevents partial commits on mid-run failure.
    if (dryRun) {
      if (orphanedHistoryCount > 0) {
        console.log(`[DRY-RUN] Would delete ${orphanedHistoryCount} orphaned history entries`);
        totalCleaned += orphanedHistoryCount;
      }
      if (orphanedVectorCount > 0) {
        console.log(`[DRY-RUN] Would delete ${orphanedVectorCount} orphaned vectors`);
        totalCleaned += orphanedVectorCount;
      }
    } else if (orphanedHistoryCount > 0 || orphanedVectorCount > 0) {
      console.log('\n[Step 3] Deleting all orphans in a single atomic transaction...');

      const atomicCleanup = database.transaction(() => {
        if (!database) throw new Error('Database connection lost');

        // Delete orphaned history entries
        if (hasHistoryTable && orphanedHistoryCount > 0) {
          const historyDeleteResult = database.prepare(`
            DELETE FROM memory_history
            WHERE memory_id NOT IN (SELECT id FROM memory_index)
          `).run();
          console.log(`Deleted ${historyDeleteResult.changes} orphaned history entries`);
          totalCleaned += historyDeleteResult.changes;
        }

        // Delete orphaned vector entries
        if (orphanedVectorCount > 0) {
          const vectorDeleteResult = database.prepare(`
            DELETE FROM vec_memories
            WHERE rowid NOT IN (SELECT id FROM memory_index)
          `).run();
          console.log(`Deleted ${vectorDeleteResult.changes} orphaned vectors`);
          totalCleaned += vectorDeleteResult.changes;
        }
      });

      atomicCleanup();
      console.log(`Atomic cleanup committed: ${totalCleaned} total entries removed`);
    }

    // STEP 4: Verify and report
    console.log('\n[Step 4] Verification...');
    const memoryCount: CountResult = database.prepare('SELECT COUNT(*) as count FROM memory_index').get() as CountResult;
    const vectorCount: CountResult = database.prepare('SELECT COUNT(*) as count FROM vec_memories').get() as CountResult;

    let historyCount: CountResult = { count: 0 };
    try {
      historyCount = database.prepare('SELECT COUNT(*) as count FROM memory_history').get() as CountResult;
    } catch (_e: unknown) {
      if (_e instanceof Error) {
        // Table may not exist
      }
    }

    console.log('\nFinal counts:');
    console.log(`  Memories: ${memoryCount.count}`);
    console.log(`  Vectors:  ${vectorCount.count}`);
    console.log(`  History:  ${historyCount.count}`);
    console.log(`\nTotal cleaned: ${totalCleaned}${dryRun ? ' (dry-run, nothing actually deleted)' : ''}`);

    database.close();
    releaseDbInstanceLocks();
    console.log(`\nCleanup ${dryRun ? 'preview' : 'completed'} successfully`);
    process.exit(0);
  } catch (error: unknown) {
    const errMsg = error instanceof Error ? error.message : String(error);
    console.error('[cleanup-orphaned-vectors] Error:', errMsg);
    if (database) {
      try {
        database.close();
      } catch (_closeErr: unknown) {
        if (_closeErr instanceof Error) {
          // Ignore close errors
        }
      }
    }
    releaseDbInstanceLocks();
    process.exit(1);
  }
}

/* ───────────────────────────────────────────────────────────────
   4. INITIALIZE
------------------------------------------------------------------*/

if (isMainModule(import.meta.url)) {
  main();
}

/* ───────────────────────────────────────────────────────────────
   5. EXPORTS
------------------------------------------------------------------*/

export { main };

#!/usr/bin/env node
// ---------------------------------------------------------------
// MODULE: Rank Memories
// ---------------------------------------------------------------
// ───────────────────────────────────────────────────────────────
// 1. RANK MEMORIES
// ───────────────────────────────────────────────────────────────
// Computes composite ranking scores for memories and folders with recency decay

import * as fs from 'fs';

/* ───────────────────────────────────────────────────────────────
   1. IMPORTS FROM FOLDER-SCORING
------------------------------------------------------------------*/

import {
  isArchived,
  getArchiveMultiplier,
  computeRecencyScore,
  computeSingleFolderScore,
  simplifyFolderPath,
  findTopTier,
  findLastActivity,
  TIER_WEIGHTS,
  SCORE_WEIGHTS,
  DECAY_RATE,
} from '@spec-kit/shared/scoring/folder-scoring';
import type { FolderMemoryInput } from '@spec-kit/shared/scoring/folder-scoring';
import { isMainModule } from '../lib/esm-entry.js';

/* ───────────────────────────────────────────────────────────────
   2. INTERFACES
------------------------------------------------------------------*/

/** Raw memory record read from input data. */
export interface RawMemory {
  id?: number;
  title?: string;
  specFolder?: string;
  importanceTier?: string;
  createdAt?: string;
  updatedAt?: string;
  filePath?: string | null;
  triggerCount?: number;
  importanceWeight?: number;
}

/** Memory record normalized for ranking and reporting. */
export interface NormalizedMemory {
  id: string | number;
  title: string;
  specFolder: string;
  importanceTier: string;
  createdAt: string;
  updatedAt: string;
  filePath: string | null;
  triggerCount: number;
  importanceWeight: number;
  /** Index signature for FolderMemoryInput compatibility (Record<string, unknown>) */
  [key: string]: unknown;
}

/** Ranked constitutional memory entry included in output summaries. */
export interface ConstitutionalEntry {
  id: string | number;
  title: string;
  specFolder: string;
  simplified: string;
}

/** Folder-level aggregate score entry used in ranking output. */
export interface FolderScoreEntry {
  folder: string;
  simplified: string;
  score: number;
  memoryCount: number;
  lastUpdate: string;
  lastUpdateRelative: string;
  topTier: string;
  isArchived: boolean;
}

/** Recent memory entry included in ranking summaries. */
export interface RecentMemoryEntry {
  id: string | number;
  title: string;
  specFolder: string;
  simplified: string;
  updatedAt: string;
  updatedAtRelative: string;
  tier: string;
}

/** Aggregate result returned from ranking memory records. */
export interface ProcessingResult {
  constitutional: ConstitutionalEntry[];
  recentlyActive: FolderScoreEntry[];
  highImportance: FolderScoreEntry[];
  recentMemories: RecentMemoryEntry[];
  stats: {
    totalMemories: number;
    totalFolders: number;
    activeFolders: number;
    archivedFolders: number;
    showingArchived: boolean;
  };
}

/** Options controlling memory ranking and output generation. */
export interface ProcessingOptions {
  showArchived?: boolean;
  folderLimit?: number;
  memoryLimit?: number;
}

/** CLI options accepted by the memory ranking script. */
export interface CLIOptions extends ProcessingOptions {
  format?: string;
  filePath?: string | null;
}

/* ───────────────────────────────────────────────────────────────
   3. HELPER FUNCTIONS
------------------------------------------------------------------*/

function formatRelativeTime(timestamp: string): string {
  const date = new Date(timestamp);
  if (isNaN(date.getTime())) {
    return 'unknown';
  }

  const daysSince = (Date.now() - date.getTime()) / (1000 * 60 * 60 * 24);

  if (daysSince < 0) return 'future';
  if (daysSince < 1 / 24) return 'just now';
  if (daysSince < 1) return `${Math.floor(daysSince * 24)}h ago`;
  if (daysSince < 7) return `${Math.floor(daysSince)}d ago`;
  if (daysSince < 30) return `${Math.floor(daysSince / 7)}w ago`;
  if (daysSince < 365) return `${Math.floor(daysSince / 30)}mo ago`;
  return `${Math.floor(daysSince / 365)}y ago`;
}

function computeFolderScore(folderPath: string, folderMemories: NormalizedMemory[]): number {
  // NormalizedMemory is structurally compatible with FolderMemoryInput (id: string|number vs string is the only diff)
  const result = computeSingleFolderScore(folderPath, folderMemories as FolderMemoryInput[]);
  return result.score;
}

function normalizeMemory(m: RawMemory): NormalizedMemory {
  return {
    id: m.id ?? 0,
    title: m.title ?? 'Untitled',
    specFolder: m.specFolder ?? 'unknown',
    importanceTier: m.importanceTier ?? 'normal',
    createdAt: m.createdAt ?? new Date().toISOString(),
    updatedAt: m.updatedAt ?? m.createdAt ?? new Date().toISOString(),
    filePath: m.filePath ?? null,
    triggerCount: m.triggerCount ?? 0,
    importanceWeight: m.importanceWeight ?? 0.5
  };
}

/* ───────────────────────────────────────────────────────────────
   4. MAIN PROCESSING
------------------------------------------------------------------*/

function processMemories(rawMemories: RawMemory[], options: ProcessingOptions = {}): ProcessingResult {
  const {
    showArchived = false,
    folderLimit = 3,
    memoryLimit = 5
  } = options;

  const memories: NormalizedMemory[] = rawMemories.map(normalizeMemory);

  const constitutional: ConstitutionalEntry[] = memories
    .filter((m) => m.importanceTier === 'constitutional')
    .slice(0, folderLimit)
    .map((m) => ({
      id: m.id,
      title: m.title,
      specFolder: m.specFolder,
      simplified: simplifyFolderPath(m.specFolder)
    }));

  const folderMap = new Map<string, NormalizedMemory[]>();
  for (const memory of memories) {
    const folder = memory.specFolder || 'unknown';
    if (!folderMap.has(folder)) {
      folderMap.set(folder, []);
    }
    const folderList = folderMap.get(folder);
    if (folderList) folderList.push(memory);
  }

  const folderScores: FolderScoreEntry[] = [];
  for (const [folder, folderMemories] of folderMap) {
    const isArchivedFolder: boolean = isArchived(folder);

    if (isArchivedFolder && !showArchived) continue;

    const score: number = computeFolderScore(folder, folderMemories);
    const topTier: string = findTopTier(folderMemories as FolderMemoryInput[]);
    const lastActivity: string = findLastActivity(folderMemories as FolderMemoryInput[]);

    folderScores.push({
      folder,
      simplified: simplifyFolderPath(folder),
      score: Math.round(score * 1000) / 1000,
      memoryCount: folderMemories.length,
      lastUpdate: lastActivity,
      lastUpdateRelative: formatRelativeTime(lastActivity),
      topTier: topTier,
      isArchived: isArchivedFolder
    });
  }

  folderScores.sort((a, b) => b.score - a.score);

  const highImportance: FolderScoreEntry[] = folderScores
    .filter((f) => f.topTier === 'critical' || f.topTier === 'constitutional')
    .filter((f) => !f.isArchived)
    .slice(0, folderLimit);

  const recentlyActive: FolderScoreEntry[] = folderScores
    .filter((f) => !f.isArchived)
    .slice(0, folderLimit);

  const recentMemories: RecentMemoryEntry[] = [...memories]
    .filter((m) => m.importanceTier !== 'constitutional')
    .filter((m) => showArchived || !isArchived(m.specFolder))
    .sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
    .slice(0, memoryLimit)
    .map((m) => ({
      id: m.id,
      title: m.title,
      specFolder: m.specFolder,
      simplified: simplifyFolderPath(m.specFolder),
      updatedAt: m.updatedAt,
      updatedAtRelative: formatRelativeTime(m.updatedAt),
      tier: m.importanceTier || 'normal'
    }));

  const allFolders: Array<{ folder: string; isArchived: boolean }> = [];
  for (const [folder] of folderMap) {
    allFolders.push({
      folder,
      isArchived: isArchived(folder)
    });
  }
  const archivedCount: number = allFolders.filter((f) => f.isArchived).length;

  return {
    constitutional,
    recentlyActive,
    highImportance,
    recentMemories,
    stats: {
      totalMemories: memories.length,
      totalFolders: folderMap.size,
      activeFolders: folderMap.size - archivedCount,
      archivedFolders: archivedCount,
      showingArchived: showArchived
    }
  };
}

/* ───────────────────────────────────────────────────────────────
   5. CLI INTERFACE
------------------------------------------------------------------*/

function readStdin(): Promise<string> {
  return new Promise((resolve, reject) => {
    let data = '';
    process.stdin.setEncoding('utf8');

    if (process.stdin.isTTY) {
      resolve('');
      return;
    }

    process.stdin.on('readable', () => {
      let chunk: string | null;
      while ((chunk = process.stdin.read() as string | null) !== null) {
        data += chunk;
      }
    });

    process.stdin.on('end', () => resolve(data));
    process.stdin.on('error', reject);
  });
}

function parseArgs(args: string[]): CLIOptions {
  const options: CLIOptions = {
    showArchived: false,
    folderLimit: 3,
    memoryLimit: 5,
    format: 'full',
    filePath: null
  };

  for (let i = 0; i < args.length; i++) {
    const arg = args[i];

    if (arg === '--show-archived') {
      options.showArchived = true;
    } else if (arg === '--folder-limit' && args[i + 1]) {
      options.folderLimit = parseInt(args[++i], 10) || 3;
    } else if (arg === '--memory-limit' && args[i + 1]) {
      options.memoryLimit = parseInt(args[++i], 10) || 5;
    } else if (arg === '--format' && args[i + 1]) {
      options.format = args[++i];
    } else if (arg.startsWith('--file=')) {
      options.filePath = arg.slice(7);
    } else if (!arg.startsWith('--') && (arg.endsWith('.json') || fs.existsSync(arg))) {
      options.filePath = arg;
    }
  }

  return options;
}

function showHelp(): void {
  console.log(`
rank-memories.js - Compute composite ranking scores for memories and folders

Usage:
  cat memories.json | node rank-memories.js [options]
  node rank-memories.js /path/to/memories.json [options]

Options:
  --show-archived     Include archived folders in output
  --folder-limit N    Max folders per section (default: 3)
  --memory-limit N    Max recent memories (default: 5)
  --format compact    Output format (compact|full)
  --help, -h          Show this help
`);
}

/* ───────────────────────────────────────────────────────────────
   6. ENTRY POINT
------------------------------------------------------------------*/

async function main(): Promise<void> {
  const args = process.argv.slice(2);

  if (args.includes('--help') || args.includes('-h')) {
    showHelp();
    process.exit(0);
  }

  const options = parseArgs(args);

  let inputData: string;
  try {
    if (options.filePath) {
      inputData = fs.readFileSync(options.filePath, 'utf8');
    } else {
      inputData = await readStdin();
    }
  } catch (err: unknown) {
    const errMsg = err instanceof Error ? err.message : String(err);
    console.error(`Error reading input: ${errMsg}`);
    process.exit(1);
  }

  if (!inputData || inputData.trim() === '') {
    console.error('Error: No input data provided. Pipe JSON or specify a file path.');
    console.error('Run with --help for usage information.');
    process.exit(1);
  }

  let parsedMemories: RawMemory[] | null = null;
  try {
    const parsed = JSON.parse(inputData) as unknown;
    if (Array.isArray(parsed)) {
      parsedMemories = parsed as RawMemory[];
    } else if (
      typeof parsed === 'object' &&
      parsed !== null &&
      'results' in parsed &&
      Array.isArray((parsed as { results?: unknown }).results)
    ) {
      parsedMemories = (parsed as { results: RawMemory[] }).results;
    } else {
      throw new Error('Input JSON must be an array or an object with a results array');
    }
  } catch (err: unknown) {
    const errMsg = err instanceof Error ? err.message : String(err);
    console.error(`Error parsing JSON: ${errMsg}`);
    process.exit(1);
    return;
  }

  if (!parsedMemories) {
    return;
  }

  const memories = parsedMemories;
  const result = processMemories(memories, {
    showArchived: options.showArchived,
    folderLimit: options.folderLimit,
    memoryLimit: options.memoryLimit
  });

  if (options.format === 'compact') {
    console.log(JSON.stringify(result));
  } else {
    console.log(JSON.stringify(result, null, 2));
  }
}

// Guard main() execution to prevent side effects on import
if (isMainModule(import.meta.url)) {
  main().catch((err: unknown) => {
    const errMsg = err instanceof Error ? err.message : String(err);
    console.error(`Error: ${errMsg}`);
    process.exit(1);
  });
}

/* ───────────────────────────────────────────────────────────────
   7. EXPORTS
------------------------------------------------------------------*/

export {
  // Re-exported from folder-scoring
  isArchived,
  getArchiveMultiplier,
  computeRecencyScore,
  simplifyFolderPath,
  TIER_WEIGHTS,
  SCORE_WEIGHTS,
  DECAY_RATE,
  // Local functions
  formatRelativeTime,
  computeFolderScore,
  processMemories,
};

