        ownerRaw = fsSync.readFileSync(path.join(lockPath, 'owner'), 'utf8');
    }
    catch (_error) {
        return 'unknown';
    }
    const ownerPid = Number(ownerRaw.split(/\r?\n/, 1)[0]?.trim());
    if (!Number.isInteger(ownerPid) || ownerPid <= 0) {
