}
function createCanonicalSaveLock(lockPath) {
    fsSync.mkdirSync(lockPath);
    fsSync.writeFileSync(path.join(lockPath, 'owner'), `${process.pid}\n${new Date().toISOString()}\n`, 'utf8');
